import React, { useCallback, useEffect, useRef, useState } from "react";
import { Link } from "react-router-dom";
import "./LilAgents.css";

const prefersReducedMotion = () =>
  typeof window !== "undefined" &&
  window.matchMedia &&
  window.matchMedia("(prefers-reduced-motion: reduce)").matches;

// Two lil companions that stroll on top of the hero stat tiles.
// Clicking one opens its mini glass terminal.
const AGENTS = [
  {
    id: "bolt",
    name: "Bolt",
    role: "builder bot",
    hueA: "#ff7847",
    hueB: "#ff4d8d",
    phrases: [
      "shipping ideas…",
      "compiling dreams ⚙️",
      "deploying to prod 🚀",
      "0 bugs found (today)",
      "refactoring reality…",
    ],
    cmd: "$ bolt status",
    lines: [
      "▸ 26+ projects shipped",
      "▸ 4 systems in production",
      "✓ currently building at CAMS",
    ],
  },
  {
    id: "pixel",
    name: "Pixel",
    role: "research bot",
    hueA: "#7c5cff",
    hueB: "#38bdf8",
    phrases: [
      "reading 60+ RAG nodes…",
      "connecting the dots…",
      "thinking really hard 🧠",
      "benchmarking vibes…",
      "found a cool paper!",
    ],
    cmd: '$ pixel ask "what\'s inside?"',
    lines: [
      "▸ RAG brain · 60+ knowledge nodes",
      "▸ 6 collaborating agents",
      "✓ all real, all running",
    ],
  },
];

function AgentSprite({ agent }) {
  const gid = `lil-body-${agent.id}`;
  return (
    <svg className="lil-svg" viewBox="0 0 72 78" aria-hidden="true">
      <defs>
        <linearGradient id={gid} x1="0" y1="0" x2="1" y2="1">
          <stop offset="0" stopColor={agent.hueA} />
          <stop offset="1" stopColor={agent.hueB} />
        </linearGradient>
      </defs>
      <ellipse className="lil-shadow" cx="36" cy="74" rx="16" ry="3.5" />
      <g className="lil-bob">
        <line className="lil-antenna" x1="36" y1="15" x2="36" y2="7" />
        <circle
          className="lil-antenna-tip"
          cx="36"
          cy="6"
          r="3"
          fill={agent.hueA}
        />
        <g className="lil-arm lil-arm-l">
          <rect
            x="6"
            y="34"
            width="9"
            height="15"
            rx="4.5"
            fill={`url(#${gid})`}
          />
        </g>
        <g className="lil-arm lil-arm-r">
          <rect
            x="57"
            y="34"
            width="9"
            height="15"
            rx="4.5"
            fill={`url(#${gid})`}
          />
        </g>
        <rect
          className="lil-foot lil-foot-l"
          x="21"
          y="61"
          width="11"
          height="9"
          rx="4.5"
        />
        <rect
          className="lil-foot lil-foot-r"
          x="40"
          y="61"
          width="11"
          height="9"
          rx="4.5"
        />
        <rect
          x="12"
          y="14"
          width="48"
          height="50"
          rx="16"
          fill={`url(#${gid})`}
        />
        <path className="lil-shine" d="M19 23 Q30 13 46 17" />
        <rect
          className="lil-face"
          x="20"
          y="26"
          width="32"
          height="22"
          rx="10"
        />
        <g className="lil-eyes">
          <circle className="lil-eye" cx="30" cy="36" r="3.4" />
          <circle className="lil-eye" cx="42" cy="36" r="3.4" />
        </g>
        <path className="lil-mouth" d="M32 42.5 Q36 45.5 40 42.5" />
      </g>
    </svg>
  );
}

function LilAgents() {
  const [bubble, setBubble] = useState(null); // { agentId, text }
  const [openId, setOpenId] = useState(null);
  const [spinId, setSpinId] = useState(null); // alarm-shake + 3D spin on click
  const perchRef = useRef(null);
  const phraseIdx = useRef([0, 0]);

  // Alternate thought bubbles between the two agents
  useEffect(() => {
    let turn = 0;
    let hide = null;
    const show = () => {
      const agent = AGENTS[turn % 2];
      const i = phraseIdx.current[turn % 2];
      setBubble({
        agentId: agent.id,
        text: agent.phrases[i % agent.phrases.length],
      });
      phraseIdx.current[turn % 2] = i + 1;
      turn += 1;
      hide = setTimeout(() => setBubble(null), 3000);
    };
    show();
    const id = setInterval(show, 5600);
    return () => {
      clearInterval(id);
      if (hide) clearTimeout(hide);
    };
  }, []);

  // Pupils follow the cursor (desktop pointers only)
  useEffect(() => {
    if (prefersReducedMotion()) return;
    if (window.matchMedia && !window.matchMedia("(pointer: fine)").matches)
      return;
    const perch = perchRef.current;
    if (!perch) return;
    let raf = null;
    const onMove = (e) => {
      if (raf) return;
      raf = requestAnimationFrame(() => {
        raf = null;
        perch.querySelectorAll(".lil-svg").forEach((svg) => {
          const r = svg.getBoundingClientRect();
          const dx = e.clientX - (r.left + r.width / 2);
          const dy = e.clientY - (r.top + r.height / 2);
          const len = Math.max(Math.hypot(dx, dy), 1);
          svg.style.setProperty("--eye-x", `${(dx / len) * 2.2}px`);
          svg.style.setProperty("--eye-y", `${(dy / len) * 1.6}px`);
        });
      });
    };
    window.addEventListener("mousemove", onMove, { passive: true });
    return () => {
      window.removeEventListener("mousemove", onMove);
      if (raf) cancelAnimationFrame(raf);
    };
  }, []);

  // Close the mini window on Escape or outside click
  useEffect(() => {
    if (!openId) return;
    const onKey = (e) => {
      if (e.key === "Escape") setOpenId(null);
    };
    const onClick = (e) => {
      if (perchRef.current && !perchRef.current.contains(e.target))
        setOpenId(null);
    };
    document.addEventListener("keydown", onKey);
    document.addEventListener("mousedown", onClick);
    return () => {
      document.removeEventListener("keydown", onKey);
      document.removeEventListener("mousedown", onClick);
    };
  }, [openId]);

  const toggle = useCallback((id) => {
    setOpenId((cur) => (cur === id ? null : id));
    if (!prefersReducedMotion()) {
      setSpinId(id);
      setTimeout(() => setSpinId((cur) => (cur === id ? null : cur)), 1100);
    }
  }, []);

  return (
    <div className="pj-agents-perch" ref={perchRef}>
      {AGENTS.map((agent, i) => (
        <div
          key={agent.id}
          className={`lil-agent lil-agent-${i} ${
            openId === agent.id ? "lil-open" : ""
          } ${spinId === agent.id ? "lil-spin" : ""}`}
          style={{ "--lil-a": agent.hueA, "--lil-b": agent.hueB }}
        >
          {bubble && bubble.agentId === agent.id && openId !== agent.id && (
            <div className="lil-bubble" role="status">
              {bubble.text}
            </div>
          )}

          {openId === agent.id && (
            <div className="lil-popover">
              <div className="lil-popover-bar">
                <span className="lil-dot lil-dot-r" />
                <span className="lil-dot lil-dot-y" />
                <span className="lil-dot lil-dot-g" />
                <span className="lil-popover-title">
                  {agent.name} · {agent.role}
                </span>
              </div>
              <div className="lil-popover-body">
                <p className="lil-line lil-line-cmd">{agent.cmd}</p>
                {agent.lines.map((line, li) => (
                  <p
                    className="lil-line"
                    style={{ "--lil-delay": `${0.25 + li * 0.3}s` }}
                    key={li}
                  >
                    {line}
                  </p>
                ))}
                <Link className="lil-popover-link" to="/myspace">
                  meet all 9 live tools →
                </Link>
              </div>
            </div>
          )}

          <button
            type="button"
            className="lil-hit"
            onClick={() => toggle(agent.id)}
            aria-label={`Chat with ${agent.name}, ${agent.role}`}
            aria-expanded={openId === agent.id}
          >
            <AgentSprite agent={agent} />
          </button>
          {/* <span className="lil-oof" aria-hidden="true">
            oof!
          </span> */}
          <span className="lil-name">{agent.name}</span>
        </div>
      ))}
    </div>
  );
}

export default LilAgents;
