// Extract the most relevant year from a timeline string ("June 2024 - Present", "2025")
const extractYear = (timeline) => {
  if (!timeline) return null;
  if (/present/i.test(timeline)) {
    const matches = timeline.match(/(20\d{2})/g);
    if (matches && matches.length) return matches[matches.length - 1];
    return "Present";
  }
  const matches = timeline.match(/(20\d{2})/g);
  if (!matches) return null;
  return matches[matches.length - 1];
};

// Build a haystack string for searching/filtering a single project
const buildHaystack = (project) => {
  const techNames = (project.languages || [])
    .map((l) => (l.name || "").toLowerCase())
    .join(" ");
  return `${(project.name || "").toLowerCase()} ${(
    project.description || ""
  ).toLowerCase()} ${techNames}`;
};

const matchesCategory = (project, categoryId) => {
  if (categoryId === "ALL") return true;
  const cat = FILTER_CATEGORIES.find((c) => c.id === categoryId);
  if (!cat || !cat.keywords) return true;
  const hay = buildHaystack(project);
  return cat.keywords.some((kw) => hay.includes(kw.toLowerCase()));
};

const matchesSearch = (project, query) => {
  const q = query.trim().toLowerCase();
  if (!q) return true;
  return buildHaystack(project).includes(q);
};

// Pull a headline number out of an impact sentence:
// "95% retrieval precision with citation enforcement" -> { value: "95%", label: "retrieval precision…" }
const parseMetric = (sentence) => {
  if (!sentence) return null;
  const m = sentence.match(/([~<>≈]?\$?\d[\d,.]*\s?(?:%|\+|x|k|K|M)?\+?)/);
  if (!m) return null;
  let label = sentence.replace(m[1], "").replace(/\s+/g, " ").trim();
  label = label.replace(/^[-–—:,.\s]+|[-–—:,.\s]+$/g, "");
  if (label.length > 64) label = label.slice(0, 61) + "…";
  return { value: m[1].trim(), label };
};

// Split "CAMS Lens 🔍 — SEBI-Grounded Compliance Intelligence Platform"
// into a short title and a tagline
const splitName = (name) => {
  if (!name) return { title: "", tagline: "" };
  const parts = name.split(/\s+—\s+|\s+-\s+/);
  if (parts.length >= 2) {
    return {
      title: parts[0].trim(),
      tagline: parts.slice(1).join(" — ").trim(),
    };
  }
  return { title: name.trim(), tagline: "" };
};

const prefersReducedMotion = () =>
  typeof window !== "undefined" &&
  window.matchMedia &&
  window.matchMedia("(prefers-reduced-motion: reduce)").matches;

// Words the hero title cycles through — first one is the widest and
// doubles as the ghost that reserves layout width
const ROTATE_WORDS = ["production.", "products.", "reality.", "impact."];

// ============================================
// Count-up number — animates when scrolled into view
// ============================================
function CountUp({ value, suffix = "" }) {
  const ref = useRef(null);
  const [display, setDisplay] = useState(prefersReducedMotion() ? value : 0);

  useEffect(() => {
    if (prefersReducedMotion()) {
      setDisplay(value);
      return;
    }
    const el = ref.current;
    if (!el) return;
    let raf = null;
    const io = new IntersectionObserver(
      ([entry]) => {
        if (!entry.isIntersecting) return;
        io.disconnect();
        const start = performance.now();
        const dur = 1100;
        const tick = (now) => {
          const t = Math.min((now - start) / dur, 1);
          const eased = 1 - Math.pow(1 - t, 3);
          setDisplay(Math.max(0, Math.min(value, Math.round(eased * value))));
          if (t < 1) raf = requestAnimationFrame(tick);
        };
        raf = requestAnimationFrame(tick);
      },
      { threshold: 0.4 }
    );
    io.observe(el);
    return () => {
      io.disconnect();
      if (raf) cancelAnimationFrame(raf);
    };
  }, [value]);

  return (
    <span ref={ref}>
      {display}
      {suffix}
    </span>
  );
}

// ============================================
// Featured rail — scroll-driven horizontal cinema
// The section pins for N viewport-heights; vertical scroll glides the
// panels sideways with parallax + focus scaling on the active one.
// ============================================
const DECK_HUES = [
  { a: "#ff7847", b: "#ff4d8d" }, // coral → pink
  { a: "#7c5cff", b: "#38bdf8" }, // violet → sky
  { a: "#10b981", b: "#a3e635" }, // emerald → lime
];

function FeaturedRail({ items, theme, onExplore }) {
  const sectionRef = useRef(null);
  const viewportRef = useRef(null);
  const trackRef = useRef(null);
  const fillRef = useRef(null);
  const [active, setActive] = useState(0);
  const activeIdxRef = useRef(0);

  useEffect(() => {
    if (prefersReducedMotion()) return;
    const section = sectionRef.current;
    const viewport = viewportRef.current;
    const track = trackRef.current;
    if (!section || !viewport || !track) return;
    const panels = Array.from(track.children);
    const n = panels.length;
    if (n === 0) return;
    let raf = null;

    const update = () => {
      raf = null;
      // Below 900px the CSS falls back to a vertical list — clear inline styles
      if (window.innerWidth <= 900) {
        track.style.transform = "";
        panels.forEach((panel) => {
          const card = panel.firstElementChild;
          if (card) {
            card.style.transform = "";
            card.style.opacity = "";
          }
        });
        return;
      }
      const rect = section.getBoundingClientRect();
      const vh = window.innerHeight;
      const total = rect.height - vh || 1;
      const p = Math.min(Math.max(-rect.top / total, 0), 1);
      const vpW = viewport.clientWidth;
      const pos = p * (n - 1);

      track.style.transform = `translate3d(${-pos * vpW}px, 0, 0)`;

      panels.forEach((panel, i) => {
        const card = panel.firstElementChild;
        if (!card) return;
        const delta = pos - i;
        const dist = Math.min(Math.abs(delta), 1);
        card.style.transform = `translateX(${delta * -70}px) scale(${
          1 - dist * 0.08
        })`;
        card.style.opacity = `${1 - dist * 0.4}`;
      });

      if (fillRef.current) {
        fillRef.current.style.transform = `scaleX(${p})`;
      }
      const idx = Math.min(Math.round(pos), n - 1);
      if (idx !== activeIdxRef.current) {
        activeIdxRef.current = idx;
        setActive(idx);
      }
    };

    const onScroll = () => {
      if (!raf) raf = requestAnimationFrame(update);
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    window.addEventListener("resize", onScroll);
    update();
    return () => {
      window.removeEventListener("scroll", onScroll);
      window.removeEventListener("resize", onScroll);
      if (raf) cancelAnimationFrame(raf);
    };
  }, [items.length]);

  // Jump to panel i by scrolling the window to the matching rail offset
  const jumpTo = useCallback(
    (i) => {
      const section = sectionRef.current;
      if (!section) return;
      const n = items.length;
      const vh = window.innerHeight;
      const top = section.getBoundingClientRect().top + window.scrollY;
      const total = section.offsetHeight - vh;
      const y = n > 1 ? top + (i / (n - 1)) * total : top;
      window.scrollTo({ top: y, behavior: "smooth" });
    },
    [items.length]
  );

  return (
    <div
      className="frail"
      ref={sectionRef}
      style={{ "--frail-n": items.length }}
    >
      <div className="frail-viewport" ref={viewportRef}>
        <div className="frail-track" ref={trackRef}>
          {items.map((repo, i) => {
            const { title, tagline } = splitName(repo.name);
            const hue = DECK_HUES[i % DECK_HUES.length];
            const metrics = (repo?.details?.impact || [])
              .map(parseMetric)
              .filter(Boolean)
              .slice(0, 3);
            const isOngoing = /present/i.test(repo?.details?.timeline || "");
            const year = extractYear(repo?.details?.timeline);
            const isGitHub = repo.url?.includes("github.com");

            return (
              <div className="frail-panel" key={`rail-${i}`}>
                <article
                  className="fdeck-card frail-card"
                  style={{
                    "--hue-a": hue.a,
                    "--hue-b": hue.b,
                  }}
                >
                  <div className="fdeck-glow" aria-hidden="true" />
                  <div className="fdeck-art" aria-hidden="true">
                    <span className="fdeck-art-grid" />
                    <span className="fdeck-orbit fdeck-orbit-1" />
                    <span className="fdeck-orbit fdeck-orbit-2" />
                    <span className="fdeck-comet" />
                  </div>
                  <span className="fdeck-index" aria-hidden="true">
                    {String(i + 1).padStart(2, "0")}
                  </span>

                  <div className="fdeck-body">
                    <div className="fdeck-info">
                      <div className="fdeck-meta">
                        <span className="fdeck-chip fdeck-chip-accent">
                          Case study {String(i + 1).padStart(2, "0")}
                        </span>
                        {year && (
                          <span className="fdeck-chip">
                            {isOngoing && (
                              <span
                                className="fdeck-live-dot"
                                aria-hidden="true"
                              />
                            )}
                            {isOngoing ? `${year} — In production` : year}
                          </span>
                        )}
                      </div>

                      <h3 className="fdeck-title">{title}</h3>
                      {tagline && <p className="fdeck-tagline">{tagline}</p>}
                      <p className="fdeck-desc">{repo.description}</p>

                      <div className="fdeck-tech">
                        {(repo.languages || []).slice(0, 6).map((l) => (
                          <span className="fdeck-tech-chip" key={l.name}>
                            {l.name}
                          </span>
                        ))}
                      </div>

                      <div className="fdeck-actions">
                        <button
                          type="button"
                          className="fdeck-btn fdeck-btn-primary"
                          onClick={() => onExplore(repo)}
                        >
                          Read case study
                        </button>
                        <a
                          className="fdeck-btn fdeck-btn-ghost"
                          href={repo.url}
                          target="_blank"
                          rel="noopener noreferrer"
                        >
                          {isGitHub ? (
                            <>
                              <FaGithub aria-hidden="true" /> GitHub
                            </>
                          ) : (
                            <>
                              <FaExternalLinkAlt aria-hidden="true" /> Visit
                              live
                            </>
                          )}
                        </a>
                      </div>
                    </div>

                    <div className="fdeck-metrics">
                      {metrics.length >= 2 ? (
                        metrics.map((m, mi) => (
                          <div className="fdeck-metric" key={mi}>
                            <span className="fdeck-metric-value">
                              {m.value}
                            </span>
                            <span className="fdeck-metric-label">
                              {m.label}
                            </span>
                          </div>
                        ))
                      ) : (
                        <ul className="fdeck-impact-list">
                          {(repo?.details?.impact || [])
                            .slice(0, 4)
                            .map((imp, ii) => (
                              <li key={ii}>{imp}</li>
                            ))}
                        </ul>
                      )}
                    </div>
                  </div>
                </article>
              </div>
            );
          })}
        </div>

        {/* Progress rail: 01 ——— 03 with clickable dots */}
        <div className="frail-progress">
          <span className="frail-num">
            {String(active + 1).padStart(2, "0")}
          </span>
          <span className="frail-bar" aria-hidden="true">
            <span className="frail-bar-fill" ref={fillRef} />
          </span>
          <span className="frail-num frail-num-total">
            {String(items.length).padStart(2, "0")}
          </span>
          <span className="frail-dots">
            {items.map((repo, i) => (
              <button
                key={`dot-${i}`}
                type="button"
                className={`frail-dot ${i === active ? "active" : ""}`}
                onClick={() => jumpTo(i)}
                aria-label={`Go to case study ${i + 1}`}
              />
            ))}
          </span>
        </div>
      </div>
    </div>
  );
}

