function Projects(props) {
  const theme = props.theme;
  const [selectedProject, setSelectedProject] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState("ALL");
  const [searchQuery, setSearchQuery] = useState("");
  const [wordIndex, setWordIndex] = useState(0);

  const heroRef = useRef(null);
  const heroSpotRef = useRef(null);
  const heroInnerRef = useRef(null);
  const progressRef = useRef(null);
  const rootRef = useRef(null);

  // Featured = first 3 projects in data (CAMS Lens, CAMSCode, IDP)
  const featuredProjects = useMemo(() => (projects.data || []).slice(0, 3), []);
  const restProjects = useMemo(() => (projects.data || []).slice(3), []);

  // Aggregate metrics for the hero stats
  const stats = useMemo(() => {
    const all = projects.data || [];
    const ai = all.filter((p) => matchesCategory(p, "AI")).length;
    const covered = all.filter(
      (p) => Array.isArray(p?.details?.newsLinks) && p.details.newsLinks.length
    ).length;
    return {
      total: all.length,
      ai,
      production: 4,
      covered: covered || 1,
    };
  }, []);

  // Unique tech names for the marquee strip
  const marqueeTech = useMemo(() => {
    const seen = new Set();
    (projects.data || []).forEach((p) =>
      (p.languages || []).forEach((l) => l.name && seen.add(l.name))
    );
    return Array.from(seen);
  }, []);

  // Filter logic — applied to non-featured cards
  const filteredProjects = useMemo(() => {
    return restProjects.filter(
      (p) => matchesCategory(p, activeCategory) && matchesSearch(p, searchQuery)
    );
  }, [restProjects, activeCategory, searchQuery]);

  // Cycle the hero's rotating word
  useEffect(() => {
    if (prefersReducedMotion()) return;
    const id = setInterval(
      () => setWordIndex((i) => (i + 1) % ROTATE_WORDS.length),
      2600
    );
    return () => clearInterval(id);
  }, []);

  // Cursor-following spotlight behind the hero title (desktop pointers only)
  useEffect(() => {
    if (prefersReducedMotion()) return;
    if (window.matchMedia && !window.matchMedia("(pointer: fine)").matches)
      return;
    const hero = heroRef.current;
    const spot = heroSpotRef.current;
    if (!hero || !spot) return;
    let raf = null;
    let x = 0;
    let y = 0;
    const onMove = (e) => {
      const rect = hero.getBoundingClientRect();
      x = e.clientX - rect.left;
      y = e.clientY - rect.top;
      if (!raf) {
        raf = requestAnimationFrame(() => {
          raf = null;
          spot.style.transform = `translate(${x}px, ${y}px) translate(-50%, -50%)`;
          spot.style.opacity = "1";
        });
      }
    };
    const onLeave = () => {
      spot.style.opacity = "0";
    };
    hero.addEventListener("mousemove", onMove);
    hero.addEventListener("mouseleave", onLeave);
    return () => {
      hero.removeEventListener("mousemove", onMove);
      hero.removeEventListener("mouseleave", onLeave);
      if (raf) cancelAnimationFrame(raf);
    };
  }, []);

  // Scroll progress bar + hero parallax — single rAF-throttled listener
  useEffect(() => {
    if (prefersReducedMotion()) return;
    let raf = null;
    const update = () => {
      raf = null;
      const y = window.scrollY;
      const doc = document.documentElement;
      const max = doc.scrollHeight - window.innerHeight || 1;
      if (progressRef.current) {
        progressRef.current.style.transform = `scaleX(${Math.min(y / max, 1)})`;
      }
      if (heroInnerRef.current) {
        const fade = Math.min(y / 520, 1);
        heroInnerRef.current.style.transform = `translateY(${y * 0.22}px)`;
        heroInnerRef.current.style.opacity = `${1 - fade * 0.85}`;
      }
    };
    const onScroll = () => {
      if (!raf) raf = requestAnimationFrame(update);
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    update();
    return () => {
      window.removeEventListener("scroll", onScroll);
      if (raf) cancelAnimationFrame(raf);
    };
  }, []);

  // Generic reveal-on-scroll for [data-reveal] elements
  useEffect(() => {
    const root = rootRef.current;
    if (!root) return;
    const els = Array.from(root.querySelectorAll("[data-reveal]"));
    if (prefersReducedMotion()) {
      els.forEach((el) => el.classList.add("revealed"));
      return;
    }
    const io = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add("revealed");
            io.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.12, rootMargin: "0px 0px -40px 0px" }
    );
    els.forEach((el) => io.observe(el));
    return () => io.disconnect();
  }, [filteredProjects.length]);

  const handleExplore = useCallback((project) => {
    setSelectedProject(project);
    setIsModalOpen(true);
  }, []);

  const closeModal = useCallback(() => {
    setIsModalOpen(false);
    setTimeout(() => setSelectedProject(null), 300);
  }, []);

  const scrollToArchive = useCallback(() => {
    const el = document.getElementById("project-archive");
    if (el) el.scrollIntoView({ behavior: "smooth", block: "start" });
  }, []);

  return (
    <div
      className="projects-main projects-v2"
      data-theme={theme?.name}
      ref={rootRef}
      style={{
        "--pj-accent": theme.accentColor,
        "--pj-accent-bright": theme.accentBright,
        "--pj-text": theme.text,
        "--pj-sub": theme.secondaryText,
        "--pj-body": theme.body,
        "--pj-card": theme.projectCard,
      }}
    >
      {/* Scroll progress bar */}
      <div className="pj-progress" aria-hidden="true">
        <div className="pj-progress-fill" ref={progressRef} />
      </div>

      <Header theme={theme} setTheme={props.setTheme} />

      {/* ============= HERO ============= */}
      <section className="pj-hero" ref={heroRef}>
        <div className="pj-hero-bg" aria-hidden="true">
          <div className="pj-orb pj-orb-1" />
          <div className="pj-orb pj-orb-2" />
          <div className="pj-orb pj-orb-3" />
          <div className="pj-hero-grid" />
          <div className="pj-hero-spot" ref={heroSpotRef} />
        </div>

        <div className="pj-hero-inner" ref={heroInnerRef}>
          <p className="pj-eyebrow">
            <span className="pj-eyebrow-line" aria-hidden="true" />
            Portfolio — Selected works
          </p>
          <h1 className="pj-hero-title">
            <span className="pj-hero-line">
              {"Ideas, engineered".split(" ").map((word, wi) => (
                <span
                  className="pj-title-word"
                  style={{ animationDelay: `${0.08 + wi * 0.12}s` }}
                  key={wi}
                >
                  {word}&nbsp;
                </span>
              ))}
            </span>
            <span className="pj-hero-line pj-hero-line-accent">
              into{" "}
              <span className="pj-word-rotator">
                {/* Ghost reserves the width of the longest word */}
                <span className="pj-word-ghost" aria-hidden="true">
                  {ROTATE_WORDS[0]}
                </span>
                <span className="pj-word" key={wordIndex}>
                  {ROTATE_WORDS[wordIndex]}
                </span>
              </span>
            </span>
          </h1>
          <p className="pj-hero-sub">{projectsHeader["description"]}</p>

          {/* Lil agents strolling on top of the stat tiles */}
          <LilAgents />

          <div className="pj-hero-stats">
            <div className="pj-stat">
              <span className="pj-stat-num">
                <CountUp value={stats.total} suffix="+" />
              </span>
              <span className="pj-stat-label">Projects shipped</span>
            </div>
            <div className="pj-stat">
              <span className="pj-stat-num">
                <CountUp value={stats.ai} suffix="+" />
              </span>
              <span className="pj-stat-label">AI / agentic systems</span>
            </div>
            <div className="pj-stat">
              <span className="pj-stat-num">
                <CountUp value={stats.production} />
              </span>
              <span className="pj-stat-label">Running in production</span>
            </div>
            <div className="pj-stat">
              <span className="pj-stat-num">
                <CountUp value={stats.covered} />
              </span>
              <span className="pj-stat-label">Covered in the press</span>
            </div>
          </div>

          <button
            type="button"
            className="pj-scroll-cue"
            onClick={scrollToArchive}
            aria-label="Scroll to projects"
          >
            <span>Scroll to explore</span>
            <span className="pj-scroll-cue-track" aria-hidden="true">
              <span className="pj-scroll-cue-dot" />
            </span>
          </button>
        </div>
      </section>

      {/* ============= FEATURED — STICKY CASE-STUDY DECK ============= */}
      {featuredProjects.length > 0 && (
        <section className="pj-featured">
          <div className="pj-section-head" data-reveal>
            <span className="pj-section-kicker">01 — Featured</span>
            <h2 className="pj-section-title">Case studies</h2>
            <p className="pj-section-sub">
              Production-grade systems I designed, built, and shipped. Keep
              scrolling — the gallery glides sideways.
            </p>
          </div>
          <FeaturedRail
            items={featuredProjects}
            theme={theme}
            onExplore={handleExplore}
          />
        </section>
      )}

      {/* ============= TECH MARQUEE ============= */}
      <div className="pj-marquee" aria-hidden="true">
        <div className="pj-marquee-track">
          {[0, 1].map((copy) => (
            <div className="pj-marquee-group" key={copy}>
              {marqueeTech.map((t) => (
                <span className="pj-marquee-item" key={`${copy}-${t}`}>
                  {t}
                  <span className="pj-marquee-dot">◆</span>
                </span>
              ))}
            </div>
          ))}
        </div>
      </div>

      {/* ============= ARCHIVE ============= */}
      <section className="pj-archive" id="project-archive">
        <div className="pj-section-head" data-reveal>
          <span className="pj-section-kicker">02 — The archive</span>
          <h2 className="pj-section-title">Everything else</h2>
          <p className="pj-section-sub">
            {restProjects.length} more experiments, tools, and systems — filter
            by discipline or search the stack.
          </p>
        </div>

        {/* Sticky glass toolbar */}
        <div className="pj-toolbar">
          <div
            className="pj-filter-pills"
            role="tablist"
            aria-label="Filter projects"
          >
            {FILTER_CATEGORIES.map((cat) => {
              const count =
                cat.id === "ALL"
                  ? restProjects.length
                  : restProjects.filter((p) => matchesCategory(p, cat.id))
                      .length;
              const isActive = activeCategory === cat.id;
              return (
                <button
                  key={cat.id}
                  type="button"
                  role="tab"
                  aria-selected={isActive}
                  className={`pj-pill ${isActive ? "active" : ""}`}
                  onClick={() => setActiveCategory(cat.id)}
                >
                  {cat.label}
                  <span className="pj-pill-count">{count}</span>
                </button>
              );
            })}
          </div>

          <div className="pj-search">
            <FaSearch className="pj-search-icon" aria-hidden="true" />
            <input
              type="search"
              className="pj-search-input"
              placeholder="Search projects, tech, keywords…"
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              aria-label="Search projects"
            />
          </div>
        </div>

        {/* Grid */}
        <div className="pj-grid">
          {filteredProjects.length === 0 ? (
            <div className="pj-empty">
              <p>No projects match this filter.</p>
              <button
                type="button"
                className="pj-empty-reset"
                onClick={() => {
                  setActiveCategory("ALL");
                  setSearchQuery("");
                }}
              >
                Reset filters
              </button>
            </div>
          ) : (
            filteredProjects.map((repo, i) => (
              <div
                className="pj-grid-item"
                data-reveal
                style={{ "--reveal-delay": `${(i % 6) * 60}ms` }}
                key={`${repo.id}-${repo.name}`}
              >
                <ProjectCard
                  repo={repo}
                  theme={theme}
                  onExplore={handleExplore}
                />
              </div>
            ))
          )}
        </div>
      </section>

      {/* ============= MODAL ============= */}
      <React.Suspense fallback={null}>
        <ProjectModal
          project={selectedProject}
          theme={theme}
          isOpen={isModalOpen}
          onClose={closeModal}
        />
      </React.Suspense>

      {/* ============= CTA BAND ============= */}
      <section className="pj-cta" data-reveal>
        <p className="pj-cta-kicker">There's more where that came from</p>
        <a
          className="pj-cta-link"
          href={socialMediaLinks.github}
          target="_blank"
          rel="noopener noreferrer"
        >
          <span>Explore GitHub</span>
          <span className="pj-cta-arrow" aria-hidden="true">
            →
          </span>
        </a>
      </section>

      <Footer theme={props.theme} onToggle={props.onToggle} />
    </div>
  );
}

export { extractYear };
export default Projects;
